def gather_loss(query, keys): # query: 特征图的每个 patch token (1024个) # keys: INP token (6个)
# 计算每个 patch 到最近 INP token 的距离 distribution = 1 - cos_sim(query.unsqueeze(2), keys.unsqueeze(1)) distance, cluster_index = torch.min(distribution, dim=2)
# Loss = 所有 patch 到最近 INP 的平均距离 return distance.mean()
